"use strict";(()=>{const e=()=>{const t=document.getElementById("back-to-top");t&&(t.addEventListener("click",()=>window.scrollTo({top:0})),window.addEventListener("scroll",()=>t.classList.toggle("visible",window.scrollY>300),{passive:!0}))};document.readyState==="loading"?document.addEventListener("DOMContentLoaded",e):e()})();
